-- Tabla para persistir reglas Drools (DRL) en base de datos
-- Evita pérdida de reglas al destruir pods en AKS
CREATE TABLE IF NOT EXISTS drools_rules_config (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    rule_type VARCHAR(50) NOT NULL,
    drl_content LONGTEXT NOT NULL,
    source_file_name VARCHAR(255),
    is_active BOOLEAN DEFAULT TRUE,
    version INT DEFAULT 1,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    created_by VARCHAR(100),
    updated_by VARCHAR(100),
    INDEX idx_rule_type_active (rule_type, is_active)
);

